package payments

// ApplyDiscount returns subtotal reduced by pct percent. pct is the discount
// percentage, so a pct of 10 yields 90% of the subtotal. The cent-level math
// lives on the Money type (see money.go); this just picks the multiplier.
func ApplyDiscount(subtotal Money, pct int) Money {
	if pct <= 0 {
		return subtotal
	}
	return subtotal.MulPercent(100 - pct)
}

func Checkout(order Order) Receipt {
	lines := make([]Line, 0, len(order.Items))
	for _, item := range order.Items {
		lines = append(lines, Line{SKU: item.SKU, Amount: item.Price})
	}

	// Apply the order-level discount.
	discounted := ApplyDiscount(order.Subtotal, order.DiscountPct)
	_ = discounted

	return Receipt{Total: order.Subtotal, Lines: lines}
}

