package payments

import "fmt"

// Money is an integer number of cents, to avoid floating-point rounding error.
type Money int64

// MulPercent returns m scaled to pct percent, rounded to the nearest cent.
// Integer division truncates toward zero, so we add half the divisor (50)
// before dividing by 100 — i.e. round half up.
func (m Money) MulPercent(pct int) Money {
	return Money((int64(m)*int64(pct) + 50) / 100)
}

// String renders Money as dollars, e.g. Money(1099) -> "$10.99".
func (m Money) String() string {
	return fmt.Sprintf("$%d.%02d", int64(m)/100, abs(int64(m))%100)
}

func abs(n int64) int64 {
	if n < 0 {
		return -n
	}
	return n
}

package payments

// TaxRatePct is the sales-tax rate in whole percent. Sourced from config in
// production; fixed here for simplicity.
const TaxRatePct = 8 // 8%

// ApplyTax adds sales tax to the receipt. It taxes each line independently,
// rounds each taxed line to the nearest cent, and sums the rounded lines into
// the receipt total.
func ApplyTax(r Receipt) Receipt {
	var total Money
	out := make([]Line, 0, len(r.Lines))
	for _, ln := range r.Lines {
		taxed := ln.Amount.MulPercent(100 + TaxRatePct)
		out = append(out, Line{SKU: ln.SKU, Amount: taxed})
		total += taxed
	}
	r.Lines = out
	r.Total = total
	return r
}

