// Three identical $3.33 lines at 8% tax. Each line taxes to 3.33*1.08 = 3.5964,
// which rounds to $3.60 per line -> $10.80 summed. But the order subtotal is
// $9.99, and 9.99*1.08 = 10.7892 -> $10.79 when taxed once. The per-line
// rounding drifts a cent high; the receipt total should match the single-rounding
// figure finance expects.
func TestApplyTax_NoPerLineDrift(t *testing.T) {
	r := Receipt{Lines: []Line{
		{SKU: "A", Amount: 333},
		{SKU: "B", Amount: 333},
		{SKU: "C", Amount: 333},
	}}
	if got, want := ApplyTax(r).Total, Money(1079); got != want {
		t.Fatalf("tax total drifted: want %s, got %s", want, got)
	}
}

