// ApplyTax adds sales tax to the receipt total. It sums the (pre-tax) line
// amounts and taxes that subtotal once, rounding a single time, so per-line
// sub-cent remainders cannot accumulate into a visible drift.
func ApplyTax(r Receipt) Receipt {
	var subtotal Money
	for _, ln := range r.Lines {
		subtotal += ln.Amount
	}
	r.Total = subtotal.MulPercent(100 + TaxRatePct)
	return r
}

