// Summarize builds an order summary, applying tax through the payments
// package so totals stay consistent across the system.
func Summarize(o payments.Order) Summary {
	receipt := payments.Checkout(o)
	receipt = payments.ApplyTax(receipt)

	summary := Summary{Lines: len(receipt.Lines)}
	summary.GrandTotal = receipt.Total
	return summary
}

package payments

// Item is a single product in an order, priced in cents.
type Item struct {
	SKU   string
	Price Money
}

// Order is a customer's cart plus order-level pricing inputs.
type Order struct {
	Subtotal    Money // sum of item prices, in cents
	DiscountPct int   // order-level discount, whole percent
	Items       []Item
}

// Line is a single priced line on a receipt.
type Line struct {
	SKU    string
	Amount Money
}

// Receipt is the finalized, customer-facing total for an order. Total is the
// single source of truth for what the customer is charged.
type Receipt struct {
	Total Money
	Lines []Line
}
